// Define GraphQL query for fetching products with dynamic filters
const GET_FILTERED_PRODUCTS = gql`
  query GetFilteredProducts($category: String, $priceRange: [Float], $rating: Float) {
    products(category: $category, priceRange: $priceRange, rating: $rating) {
      id
      name
      price
      category
      rating
    }
  }
`;

const ProductFilter = () => {
  // State to manage filters
  const [filters, setFilters] = useState({
    category: '',
    priceRange: [],
    rating: 0,
  });

  // Fetch products based on filters
  const { data, loading, error } = useQuery(GET_FILTERED_PRODUCTS, {
    variables: { ...filters },
  });

  // Update filter state
  const handleFilterChange = (event) => {
    const { name, value } = event.target;
    setFilters((prevFilters) => ({
      ...prevFilters,
      [name]: name === 'priceRange' ? value.split(',').map(Number) : (name === 'rating' ? parseFloat(value) : value),
    }));
  };

  return (
    <div>
      <h2>Filter Products</h2>
      <form>
        <label>Category:
          <input type="text" name="category" value={filters.category} onChange={handleFilterChange} />
        </label>
        <label>Price Range (min,max):
          <input type="text" name="priceRange" value={filters.priceRange.join(',')} onChange={handleFilterChange} />
        </label>
        <label>Rating:
          <input type="number" step="0.1" name="rating" value={filters.rating} onChange={handleFilterChange} />
        </label>
      </form>
      {loading ? (
        <p>Loading...</p>
      ) : error ? (
        <p>Error: {error.message}</p>
      ) : (
        <div>
          {data && data.products.length > 0 ? (
            <ul>
              {data.products.map((product) => (
                <li key={product.id}>{product.name} - ${product.price} - {product.rating} stars</li>
              ))}
            </ul>
          ) : (
            <p>No products found.</p>
          )}
        </div>
      )}
    </div>
  );
};

