# Simple OAuth 2.0 token verification decorator
def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authorization header is expected with Bearer token'}), 403

        token = auth_header.split(' ')[1]
        if not verify_token(token):
            return jsonify({'error': 'Invalid or expired token'}), 403

        return f(*args, **kwargs)
    return decorated_function

@app.route('/forecast', methods=['GET'])
@require_oauth
def get_forecast():
    city = request.args.get('city')
    date = request.args.get('date')

    if not city or not date:
        return jsonify({'error': 'Both city and date parameters are required'}), 400

    try:
        query_date = datetime.strptime(date, '%Y-%m-%d')
    except ValueError:
        return jsonify({'error': 'Invalid date format, use YYYY-MM-DD'}), 400

    cache_key = f'forecast:{city}:{date}'
    cached = redis_instance.get(cache_key)
    if cached:
        return jsonify(json.loads(cached)), 200

    params = {
        'q': city,
        'appid': API_KEY,
        'units': 'metric'
    }

    try:
        response = requests.get(WEATHER_URL, params=params)
        response.raise_for_status()

        weather_data = response.json()

        # Filter forecast data for the requested date
        filtered_data = []
        for item in weather_data.get('list', []):
            forecast_time = datetime.fromtimestamp(item['dt'])
            if forecast_time.strftime('%Y-%m-%d') == date:
                filtered_data.append(item)

        if not filtered_data:
            return jsonify({'error': 'No forecast data available for the specified date'}), 404

        result = {
            'city': city,
            'date': date,
            'forecast': filtered_data
        }

        # Cache the result for 2 hours
        redis_instance.setex(cache_key, timedelta(hours=2), json.dumps(result))

        return jsonify(result), 200

    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 404:
            return jsonify({'error': f'City {city} not found'}), 404
        return jsonify({'error': f'Weather API error: {str(e)}'}), 500
    except requests.exceptions.RequestException:
        return jsonify({'error': 'Failed to connect to weather service'}), 503
    except Exception as e:
        return jsonify({'error': f'An unexpected error occurred: {str(e)}'}), 500

if __name__ == '__main__':
    app.run(debug=True)

