@method_decorator(csrf_exempt, name='dispatch')
class ArticleController(View):
    def post(self, request):
        """Store a newly created article in storage."""
        try:
            data = json.loads(request.body)

            # Validate required fields
            if not all(key in data for key in ['title', 'content', 'language_code']):
                return JsonResponse({'error': 'Missing required fields'}, status=400)

            # Create base article if parent_article_id is not provided
            if 'parent_article_id' in data and data['parent_article_id']:
                try:
                    parent_article = Article.objects.get(id=data['parent_article_id'])
                    article = parent_article
                except Article.DoesNotExist:
                    return JsonResponse({'error': 'Parent article not found'}, status=404)
            else:
                article = Article()
                article.save()

            # Create translation
            translation = ArticleTranslation.objects.create(
                article=article,
                title=data['title'],
                content=data['content'],
                language_code=data['language_code'],
                user_id=request.user.id if hasattr(request, 'user') and request.user.is_authenticated else None
            )

            return JsonResponse({
                'article': {
                    'id': translation.id,
                    'article_id': article.id,
                    'title': translation.title,
                    'content': translation.content,
                    'language_code': translation.language_code
                }
            }, status=201)

        except json.JSONDecodeError:
            return JsonResponse({'error': 'Invalid JSON'}, status=400)
        except Exception as e:
            return JsonResponse({'error': str(e)}, status=500)

    def get(self, request, article_id):
        """Display the specified article in the user's preferred language."""
        user_language = LanguagePreferenceMiddleware.get_user_language()

        try:
            # Try to get article in preferred language
            article_translation = ArticleTranslation.objects.filter(
                article_id=article_id,
                language_code=user_language
            ).first()

            if not article_translation:
                # Fallback to any available translation
                article_translation = ArticleTranslation.objects.filter(
                    article_id=article_id
                ).first()

                if not article_translation:
                    return JsonResponse({'error': 'Article not found'}, status=404)

            # Get available languages for this article
            available_languages = ArticleTranslation.objects.filter(
                article_id=article_id
            ).values_list('language_code', flat=True)

            return JsonResponse({
                'article': {
                    'id': article_translation.id,
                    'article_id': article_translation.article.id,
                    'title': article_translation.title,
                    'content': article_translation.content,
                    'language_code': article_translation.language_code,
                    'available_languages': list(available_languages)
                }
            })

        except Exception as e:
            return JsonResponse({'error': str(e)}, status=500)

    def get_translations(self, request, article_id):
        """Get all translations for an article."""
        try:
            translations = ArticleTranslation.objects.filter(
                article_id=article_id
            ).select_related('article')

            if not translations.exists():
                return JsonResponse({'error': 'Article not found'}, status=404)

            translations_data = []
            for translation in translations:
                translations_data.append({
                    'id': translation.id,
                    'title': translation.title,
                    'content': translation.content,
                    'language_code': translation.language_code
                })

            return JsonResponse({'translations': translations_data})

        except Exception as e:
            return JsonResponse({'error': str(e)}, status=500)

