from django.utils.translation import activate, get_language
from django.conf import settings

class LanguagePreferenceMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        # Get language from Accept-Language header
        accept_language = request.META.get('HTTP_ACCEPT_LANGUAGE', '')

        if accept_language:
            # Parse the Accept-Language header and get the first preference
            languages = []
            for lang in accept_language.split(','):
                lang = lang.strip().split(';')[0]  # Remove quality values
                if lang:
                    languages.append(lang.lower())

            # Find the first supported language
            supported_languages = [lang[0] for lang in settings.LANGUAGES] if hasattr(settings, 'LANGUAGES') else ['en']

            for lang in languages:
                # Check exact match first
                if lang in supported_languages:
                    activate(lang)
                    break
                # Check language prefix (e.g., 'en' for 'en-US')
                lang_prefix = lang.split('-')[0]
                if lang_prefix in supported_languages:
                    activate(lang_prefix)
                    break
            else:
                # Fallback to default language
                activate(getattr(settings, 'LANGUAGE_CODE', 'en'))
        else:
            # Fallback to default language
            activate(getattr(settings, 'LANGUAGE_CODE', 'en'))

        response = self.get_response(request)
        return response

    @staticmethod
    def get_user_language():
        return get_language()

class TrieNode {
  children: Map<string, TrieNode>;
  isEndOfWord: boolean;
  suggestions: string[];

  constructor() {
    this.children = new Map<string, TrieNode>();
    this.isEndOfWord = false;
    this.suggestions = [];
  }
}

class AutocompleteEngine {
  private root: TrieNode;
  private maxSuggestions: number;

  constructor(maxSuggestions: number = 10) {
    this.root = new TrieNode();
    this.maxSuggestions = maxSuggestions;
  }

  // Add a function name to the trie - O(m) where m is the function name length
  addFunction(functionName: string): void {
    const lowerCaseName = functionName.toLowerCase();
    let current = this.root;

    for (const char of lowerCaseName) {
      if (!current.children.has(char)) {
        current.children.set(char, new TrieNode());
      }
      current = current.children.get(char)!;

      // Store original function name in suggestions array for this node
      if (!current.suggestions.includes(functionName)) {
        current.suggestions.push(functionName);
        // Keep suggestions sorted for better UX
        current.suggestions.sort();
        // Limit the number of suggestions stored at each node
        if (current.suggestions.length > this.maxSuggestions) {
          current.suggestions.pop();
        }
      }
    }
    current.isEndOfWord = true;
  }

  // Get suggestions for a prefix - O(m) where m is the length of the prefix
  getSuggestions(prefix: string): string[] {
    const lowerCasePrefix = prefix.toLowerCase();
    let current = this.root;

    // Navigate to the last node of the prefix
    for (const char of lowerCasePrefix) {
      if (!current.children.has(char)) {
        return []; // No match found
      }
      current = current.children.get(char)!;
    }

    // Return the precomputed suggestions
    return [...current.suggestions];
  }

  // Remove a function from the trie - O(m) where m is the function name length
  removeFunction(functionName: string): boolean {
    const lowerCaseName = functionName.toLowerCase();

    // First, find all nodes that have this function name in their suggestions
    const nodesToUpdate: TrieNode[] = [];
    this.findNodesWithSuggestion(this.root, lowerCaseName, 0, nodesToUpdate, functionName);

    // Remove the function name from all affected nodes' suggestions
    for (const node of nodesToUpdate) {
      const index = node.suggestions.indexOf(functionName);
      if (index > -1) {
        node.suggestions.splice(index, 1);
      }
    }

    // Check if the function actually existed in the trie
    let current = this.root;
    for (const char of lowerCaseName) {
      if (!current.children.has(char)) {
        return false; // Function not found
      }
      current = current.children.get(char)!;
    }

    if (!current.isEndOfWord) {
      return false; // Not a complete function name
    }

    current.isEndOfWord = false;
    return true;
  }

  private findNodesWithSuggestion(
    node: TrieNode, 
    word: string, 
    depth: number, 
    nodesToUpdate: TrieNode[], 
    functionName: string
  ): void {
    // If this node contains the suggestion, add it to the list
    if (node.suggestions.includes(functionName)) {
      nodesToUpdate.push(node);
    }

    // Base case: end of word
    if (depth === word.length) {
      return;
    }

    const char = word[depth];
    if (node.children.has(char)) {
      this.findNodesWithSuggestion(
        node.children.get(char)!, 
        word, 
        depth + 1, 
        nodesToUpdate, 
        functionName
      );
    }
  }

  // Bulk add functions - O(n*m) where n is number of functions, m is average function name length
  addFunctions(functionNames: string[]): void {
    for (const functionName of functionNames) {
      this.addFunction(functionName);
    }
  }

  // Serialize the trie to string for persistence
  serialize(): string {
    // Get all function names from the trie
    const functionNames: string[] = [];
    this.collectAllFunctions(this.root, "", functionNames);
    return functionNames.join("|");
  }

  private collectAllFunctions(node: TrieNode, prefix: string, functionNames: string[]): void {
    if (node.isEndOfWord) {
      // Find the original cased version from the suggestions
      const originalCased = node.suggestions.find(s => s.toLowerCase() === prefix);
      if (originalCased) {
        functionNames.push(originalCased);
      }
    }

    for (const [char, childNode] of node.children.entries()) {
      this.collectAllFunctions(childNode, prefix + char, functionNames);
    }
  }

  // Deserialize from string to rebuild the trie
  deserialize(serialized: string): void {
    if (!serialized) {
      return;
    }

    // Reset the trie
    this.root = new TrieNode();

    // Add each function to the trie
    const functionNames = serialized.split("|");
    this.addFunctions(functionNames);
  }
}

