class WebhookService {
  // Generate HMAC signature for payload
  static generateSignature(secretKey, payload, timestamp) {
    const stringToSign = JSON.stringify(payload) + timestamp;
    return crypto
      .createHmac('sha256', secretKey)
      .update(stringToSign)
      .digest('hex');
  }

  // Verify webhook signature
  static verifySignature(payload, signature, timestamp, secretKey) {
    const expectedSignature = this.generateSignature(secretKey, payload, timestamp);
    try {
      return crypto.timingSafeEqual(
        Buffer.from(signature),
        Buffer.from(expectedSignature)
      );
    } catch (error) {
      console.error('Signature verification failed:', error);
      return false;
    }
  }

