            console.error('Failed to dispatch webhook', {
              webhookId: webhook._id,
              event,
              error: error.message
            });
          })
      );

      await Promise.allSettled(dispatchPromises);
      return true;
    } catch (error) {
      console.error(`Error dispatching event ${event}:`, error);
      throw error;
    }
  }

  // Send webhook to endpoint
