    // Check if this webhook ID is rate limited
    const webhookLimiterKey = `webhook:${webhook._id}`;
    if (!rateLimitDb.has(webhookLimiterKey)) {
      rateLimitDb.set(webhookLimiterKey, {
        remaining: 10, // 10 requests per minute per webhook
