import React from 'react';
import { Provider } from 'react-redux';
import { createStore } from 'redux';
import FilterComponent from './FilterComponent';
import ProductsComponent from './ProductsComponent';

// Redux action types
const SET_FILTER = 'SET_FILTER';

// Redux actions
export const setFilter = filter => ({
  type: SET_FILTER,
  payload: filter
});

// Redux reducer
const filterReducer = (state = 'ALL', action) => {
  switch (action.type) {
    case SET_FILTER:
      return action.payload;
    default:
      return state;
  }
};

const store = createStore(filterReducer);

const products = [
  { id: 1, name: 'Laptop', category: 'Electronics', description: 'High performance laptop' },
  { id: 2, name: 'T-Shirt', category: 'Clothing', description: 'Stylish t-shirt' },
  { id: 3, name: 'Book on React', category: 'Books', description: 'Learn React fast' },
  { id: 4, name: 'Smartphone', category: 'Electronics', description: 'Latest smartphone model' },
  { id: 5, name: 'Jeans', category: 'Clothing', description: 'Comfortable denim jeans' },
  { id: 6, name: 'JavaScript Guide', category: 'Books', description: 'Complete JavaScript reference' }
];

const App = () => {
  return (
    <Provider store={store}>
      <div className="app-container">
        <h1>Product Catalog</h1>
        <div className="content-wrapper">
          <FilterComponent />
          <ProductsComponent products={products} />
        </div>
      </div>
    </Provider>
  );
};

export default App;
