import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { IsString, IsNumber, IsUUID, IsOptional, MaxLength, IsPositive, Matches } from 'class-validator';

export class CreatePaymentDto {
  @ApiProperty({ example: 100.50, description: 'Payment amount' })
  @IsNumber()
  @IsPositive()
  amount: number;

  @ApiProperty({ example: 'USD', description: 'Currency in ISO 4217 format' })
  @IsString()
  @Matches(/^[A-Z]{3}$/, { message: 'Currency must be a valid ISO 4217 code' })
  currency: string;

  @ApiProperty({ example: '123e4567-e89b-12d3-a456-426614174000', description: 'Customer ID' })
  @IsUUID()
  customerId: string;

  @ApiPropertyOptional({ example: 'Monthly subscription payment', description: 'Payment description' })
  @IsOptional()
  @IsString()
  @MaxLength(255)
  description?: string;
}

