import { Prop, Schema, SchemaFactory } from '@nestjs/mongoose';
import { Document } from 'mongoose';

@Schema({ timestamps: true })
export class Payment extends Document {
  @Prop({ required: true })
  amount: number;

  @Prop({ required: true })
  currency: string;

  @Prop({ required: true })
  customerId: string;

  @Prop()
  description?: string;

  @Prop()
  stripePaymentIntentId?: string;

  @Prop({ default: 'pending' })
  status: string;
}

export const PaymentSchema = SchemaFactory.createForClass(Payment);

// src/payments/payment.service.ts
import { Injectable, HttpException, HttpStatus, Logger } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Connection } from 'mongoose';
import { InjectConnection } from '@nestjs/mongoose';
import { Payment } from './schemas/payment.schema';
import { CreatePaymentDto } from './dto/create-payment.dto';
import Stripe from 'stripe';

@Injectable()
export class PaymentService {
  private readonly logger = new Logger(PaymentService.name);
  private stripeClient: Stripe;

  constructor(
    @InjectModel(Payment.name) private paymentModel: Model<Payment>,
    @InjectConnection() private connection: Connection,
  ) {
    this.stripeClient = new Stripe(process.env.STRIPE_SECRET_KEY || 'sk_test_dummy', {
      apiVersion: '2023-10-16',
    });
  }

  async createPayment(createPaymentDto: CreatePaymentDto): Promise<{ paymentId: string; clientSecret: string }> {
    const session = await this.connection.startSession();
    session.startTransaction();

    try {
      // Convert amount to cents for Stripe if needed
      const stripeAmount = Math.round(createPaymentDto.amount * 100);

      // Create payment document
      const payment = new this.paymentModel({
        amount: createPaymentDto.amount,
        currency: createPaymentDto.currency,
        customerId: createPaymentDto.customerId,
        description: createPaymentDto.description,
        status: 'pending',
      });

      const savedPayment = await payment.save({ session });

      // Create Stripe payment intent
      const stripePaymentIntent = await this.stripeClient.paymentIntents.create({
        amount: stripeAmount,
        currency: createPaymentDto.currency.toLowerCase(),
        metadata: { paymentId: savedPayment.id },
        description: createPaymentDto.description || `Payment for customer ${createPaymentDto.customerId}`,
      });

      // Update payment with Stripe payment intent ID
      savedPayment.stripePaymentIntentId = stripePaymentIntent.id;
      await savedPayment.save({ session });

      // Commit transaction
      await session.commitTransaction();
      session.endSession();

      return {
        paymentId: savedPayment.id,
        clientSecret: stripePaymentIntent.client_secret,
      };
    } catch (error) {
      // Abort transaction on error
      await session.abortTransaction();
      session.endSession();

      // Log error
      this.logger.error(JSON.stringify({
        error: 'Stripe payment intent creation failed',
        details: error.message,
        stack: error.stack,
      }));

      throw new HttpException({
        error: 'Payment gateway error',
        details: error.message,
      }, HttpStatus.BAD_GATEWAY);
    }
  }
}

