      mockPaymentService.createPayment.mockResolvedValue(mockPaymentResponse);

      const result = await controller.create(mockCreatePaymentDto);

      expect(result).toEqual(mockPaymentResponse);
      expect(paymentService.createPayment).toHaveBeenCalledWith(mockCreatePaymentDto);
