describe('PaymentController (e2e)', () => {
  let app: INestApplication;
  let paymentService: PaymentService;

  const mockPaymentResponse = {
    paymentId: 'mockPaymentId',
    clientSecret: 'mockClientSecret',
  };

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    })
      .overrideProvider(PaymentService)
      .useValue({
        createPayment: jest.fn(),
      })
      .compile();

    app = moduleFixture.createNestApplication();
    app.useGlobalPipes(
      new ValidationPipe({
        whitelist: true,
        forbidNonWhitelisted: true,
        transform: true,
      }),
    );

    paymentService = app.get<PaymentService>(PaymentService);

    await app.init();
  });

  afterAll(async () => {
    await app.close();
  });

  describe('/payments (POST)', () => {
    const validPayload: CreatePaymentDto = {
      amount: 100,
      currency: 'USD',
      customerId: '123e4567-e89b-12d3-a456-426614174000',
      description: 'Test payment',
    };

    it('should return 401 without API key', () => {
      return request(app.getHttpServer())
        .post('/payments')
        .send(validPayload)
        .expect(401);
    });

    it('should return 400 with invalid payload', () => {
      const invalidPayload = {
        amount: -100, // Invalid amount
        currency: 'USD',
        customerId: '123e4567-e89b-12d3-a456-426614174000',
      };

      return request(app.getHttpServer())
        .post('/payments')
        .set('x-api-key', 'test-api-key')
        .send(invalidPayload)
        .expect(400);
    });

    it('should return 400 with invalid currency format', () => {
      const invalidPayload = {
        ...validPayload,
        currency: 'USDollar', // Invalid format
      };

      return request(app.getHttpServer())
        .post('/payments')
        .set('x-api-key', 'test-api-key')
        .send(invalidPayload)
        .expect(400);
    });

    it('should return 400 with invalid UUID', () => {
      const invalidPayload = {
        ...validPayload,
        customerId: 'not-a-uuid',
      };

      return request(app.getHttpServer())
        .post('/payments')
        .set('x-api-key', 'test-api-key')
        .send(invalidPayload)
        .expect(400);
    });

    it('should return 201 with valid payload and API key', () => {
      jest.spyOn(paymentService, 'createPayment').mockResolvedValue(mockPaymentResponse);

      return request(app.getHttpServer())
        .post('/payments')
        .set('x-api-key', 'test-api-key')
        .send(validPayload)
        .expect(201)
        .expect(mockPaymentResponse);
    });

    it('should return 502 when payment gateway fails', () => {
      jest.spyOn(paymentService, 'createPayment').mockRejectedValue({
        status: 502,
        getStatus: () => 502,
        getResponse: () => ({
          error: 'Payment gateway error',
          details: 'Stripe API error',
        }),
      });

      return request(app.getHttpServer())
        .post('/payments')
        .set('x-api-key', 'test-api-key')
        .send(validPayload)
        .expect(502)
        .expect({
          error: 'Payment gateway error',
          details: 'Stripe API error',
        });
    });
  });
});

