from flask import Flask, request, jsonify, make_response
from pymongo import MongoClient
from bson.objectid import ObjectId
from functools import wraps
import jwt
import os
from datetime import datetime

app = Flask(__name__)
app.config["SECRET_KEY"] = os.environ.get("SECRET_KEY", "your-secret-key")

client = MongoClient(os.environ.get("MONGO_URI", "mongodb://localhost:27017/"))
db = client["health_management"]
patients_collection = db["patients"]

# Pre-defined valid health conditions
valid_conditions = {"Diabetes", "Hypertension", "Asthma", "COVID-19", 
                   "Arthritis", "Depression", "Anxiety", "COPD", 
                   "Cancer", "Heart Disease", "Obesity"}

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return make_response(jsonify({"error": "Token is missing!"}), 401)

        try:
            token = token.split(" ")[1]
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
            current_user_id = data['user_id']
            # Could add additional validation for the current user here
        except Exception as e:
            return make_response(jsonify({"error": "Token is invalid!"}), 401)

        return f(current_user_id, *args, **kwargs)
    return decorated

@app.route("/patient/<patient_id>", methods=["PUT"])
@token_required
def update_patient(current_user_id, patient_id):
    if not request.is_json:
        return make_response(jsonify({"error": "Request must be JSON"}), 400)

    data = request.get_json()

    # Validate required fields
    if not all(key in data for key in ["name", "age", "conditions"]):
        return make_response(jsonify({"error": "Missing required fields"}), 400)

    # Extract data
    name = data.get("name")
    age = data.get("age")
    conditions = data.get("conditions")

    # Validate data types
    if not isinstance(name, str):
        return make_response(jsonify({"error": "Name must be a string"}), 400)

    if not isinstance(age, int):
        return make_response(jsonify({"error": "Age must be an integer"}), 400)

    if age < 0:
        return make_response(jsonify({"error": "Age must be a non-negative integer"}), 400)

    if not isinstance(conditions, list):
        return make_response(jsonify({"error": "Conditions must be a list"}), 400)

    # Validate conditions
    invalid_conditions = [c for c in conditions if c not in valid_conditions]
    if invalid_conditions:
        return make_response(jsonify({"error": f"Invalid health conditions: {', '.join(invalid_conditions)}"}), 400)

    # Update patient record in the database
    try:
        update_result = patients_collection.update_one(
            {"_id": ObjectId(patient_id)},
            {"$set": {
                "name": name, 
                "age": age, 
                "conditions": conditions,
                "updated_at": datetime.utcnow()
            }}
        )

        if update_result.matched_count == 0:
            return make_response(jsonify({"error": "No patient found with provided ID"}), 404)
    except Exception as e:
        return make_response(jsonify({"error": str(e)}), 500)

    # Return the updated patient data
    updated_patient = patients_collection.find_one({"_id": ObjectId(patient_id)})
    updated_patient["_id"] = str(updated_patient["_id"])  # Convert ObjectId to string for JSON serialization

    if "updated_at" in updated_patient:
        updated_patient["updated_at"] = updated_patient["updated_at"].isoformat()

    return jsonify(updated_patient), 200

if __name__ == "__main__":
    app.run(debug=False)

