const redis = require('redis');
const { promisify } = require('util');
const express = require('express');

class RateLimiterMiddleware {
  constructor(options = {}) {
    this.options = {
      // Default window size: 15 minutes
      windowMs: options.windowMs || 15 * 60 * 1000, 
      // Default max requests per window
      maxRequests: options.maxRequests || 100,
      // Default block duration: 1 hour
      blockDuration: options.blockDuration || 60 * 60 * 1000,
      // Redis connection options
      redisOptions: options.redisOptions || { url: process.env.REDIS_URL || 'redis://localhost:6379' },
      // Whitelist of IPs or IP ranges that won't be rate limited
      whitelistedIPs: options.whitelistedIPs || [],
      // Enable detailed logging
      enableLogging: options.enableLogging !== undefined ? options.enableLogging : true
    };

    // Set up Redis client
    this.redisClient = redis.createClient(this.options.redisOptions);
    this.redisClient.on('error', (err) => {
      console.error('Redis error:', err);
    });

    // Promisify Redis methods
    this.getAsync = promisify(this.redisClient.get).bind(this.redisClient);
    this.setAsync = promisify(this.redisClient.set).bind(this.redisClient);
    this.expireAsync = promisify(this.redisClient.expire).bind(this.redisClient);
    this.delAsync = promisify(this.redisClient.del).bind(this.redisClient);
    this.keysAsync = promisify(this.redisClient.keys).bind(this.redisClient);
    this.ttlAsync = promisify(this.redisClient.ttl).bind(this.redisClient);

    // For sorted set implementation
    this.zaddAsync = promisify(this.redisClient.zadd).bind(this.redisClient);
    this.zrangebyscoreAsync = promisify(this.redisClient.zrangebyscore).bind(this.redisClient);
    this.zremrangebyscoreAsync = promisify(this.redisClient.zremrangebyscore).bind(this.redisClient);
    this.zcountAsync = promisify(this.redisClient.zcount).bind(this.redisClient);

    // In-memory cache of blocked IPs for faster access
    this.blockedIpsCache = new Set();

    // Load blocked IPs into cache on startup
    this.loadBlockedIpsCache();
  }

  // Load blocked IPs into memory cache
  async loadBlockedIpsCache() {
    try {
      const blockedIps = await this.getBlockedIPs();
      blockedIps.forEach(item => this.blockedIpsCache.add(item.ip));
      this.log(`Loaded ${this.blockedIpsCache.size} blocked IPs into cache`);
    } catch (err) {
      this.log(`Failed to load blocked IPs cache: ${err.message}`, 'error');
    }
  }

  // Method to check if an IP is whitelisted
  isWhitelisted(ip) {
    return this.options.whitelistedIPs.includes(ip);
  }

  // Logging helper method
  log(message, level = 'info') {
    if (!this.options.enableLogging) return;

    const timestamp = new Date().toISOString();

    switch(level) {
      case 'error':
        console.error(`[${timestamp}] ERROR: ${message}`);
        break;
      case 'warn':
        console.warn(`[${timestamp}] WARN: ${message}`);
        break;
      default:
        console.log(`[${timestamp}] INFO: ${message}`);
    }
  }

  // Rate limiting middleware
  middleware() {
    return async (req, res, next) => {
      const ip = req.ip || req.connection.remoteAddress;

      // Skip rate limiting for whitelisted IPs
      if (this.isWhitelisted(ip)) {
        this.log(`Whitelisted IP: ${ip}`);
        return next();
      }

      // Quick check in memory cache first
      if (this.blockedIpsCache.has(ip)) {
        this.log(`Blocked request from banned IP (cache hit): ${ip}`, 'warn');
        return res.status(403).json({
          error: 'Access denied. Your IP address has been blocked due to suspicious activity.'
        });
      }

      const requestKey = `request:${ip}`;
      const blockedKey = `blocked:${ip}`;

      try {
        // Double-check if IP is blocked in Redis
        const isBlocked = await this.getAsync(blockedKey);
        if (isBlocked) {
          // Update cache
          this.blockedIpsCache.add(ip);
          this.log(`Blocked request from banned IP: ${ip}`, 'warn');
          return res.status(403).json({
            error: 'Access denied. Your IP address has been blocked due to suspicious activity.'
          });
        }

        // Time-based rate limiting with sorted sets
        const now = Date.now();
        const windowStart = now - this.options.windowMs;

        // Add the current request timestamp to the sorted set
        await this.zaddAsync(requestKey, now.toString(), now.toString());

        // Set expiry on the key
        await this.expireAsync(requestKey, Math.floor(this.options.windowMs / 1000) + 10);

        // Clean up old requests outside the current window
        await this.zremrangebyscoreAsync(requestKey, 0, windowStart);

        // Count requests in the current window
        const requestCount = await this.zcountAsync(requestKey, windowStart, '+inf');

        // Check if request count exceeds threshold
        if (requestCount > this.options.maxRequests) {
          await this.blockIP(ip);
          this.log(`Rate limit exceeded: ${ip} (${requestCount} requests in window)`, 'warn');
          return res.status(429).json({
            error: 'Too many requests. Your IP has been temporarily blocked.'
          });
        }

        // If we get here, request is allowed
        this.log(`Request allowed: ${ip} (${requestCount}/${this.options.maxRequests})`);
        next();
      } catch (err) {
        this.log(`Rate limiter error: ${err.message}`, 'error');
        // Fail open - let the request through if the rate limiter fails
        next();
      }
    };
  }

  // Helper method to block an IP
  async blockIP(ip) {
    // Add to Redis
    await this.setAsync(`blocked:${ip}`, Date.now().toString());
    await this.expireAsync(`blocked:${ip}`, Math.floor(this.options.blockDuration / 1000));

    // Add to memory cache
    this.blockedIpsCache.add(ip);

    // Log the blocked IP
    this.log({
      message: `IP blocked due to rate limit exceeded: ${ip}`,
      blockDuration: this.options.blockDuration
    }, 'warn');
  }

  // Admin methods for managing blocked IPs
  async getBlockedIPs() {
    try {
      const keys = await this.keysAsync('blocked:*');
      const blockedIPs = [];

      for (const key of keys) {
        const ip = key.replace('blocked:', '');
        const timestamp = await this.getAsync(key);

        // Get TTL to calculate expiry time
        const ttl = await this.ttlAsync(key);

        blockedIPs.push({
          ip,
          blockedAt: new Date(parseInt(timestamp)),
          expiresIn: `${Math.floor(ttl / 60)} minutes, ${ttl % 60} seconds`,
          expiresAt: new Date(Date.now() + (ttl * 1000))
        });
      }

      return blockedIPs;
    } catch (err) {
      this.log(`Error fetching blocked IPs: ${err.message}`, 'error');
      throw err;
    }
  }

  async unblockIP(ip) {
    try {
      await this.delAsync(`blocked:${ip}`);

      // Remove from memory cache
      this.blockedIpsCache.delete(ip);

      this.log(`IP ${ip} has been manually unblocked`);
      return true;
    } catch (err) {
      this.log(`Error unblocking IP ${ip}: ${err.message}`, 'error');
      throw err;
    }
  }

  async manuallyBlockIP(ip, duration = null) {
    try {
      const blockDuration = duration || this.options.blockDuration;
      await this.setAsync(`blocked:${ip}`, Date.now().toString());
      await this.expireAsync(`blocked:${ip}`, Math.floor(blockDuration / 1000));

      // Add to memory cache
      this.blockedIpsCache.add(ip);

      this.log(`IP ${ip} has been manually blocked for ${blockDuration/1000} seconds`);

      return true;
    } catch (err) {
      this.log(`Error blocking IP ${ip}: ${err.message}`, 'error');
      throw err;
    }
  }

  // Get rate limit status for an IP
  async getRateLimitStatus(ip) {
    try {
      const requestKey = `request:${ip}`;
      const now = Date.now();
      const windowStart = now - this.options.windowMs;

      const requestCount = await this.zcountAsync(requestKey, windowStart, '+inf');

      // Get the oldest timestamp to calculate time remaining
      const oldestRequests = await this.zrangebyscoreAsync(requestKey, windowStart, '+inf', 'LIMIT', 0, 1);
      let timeRemaining = 0;

      if (oldestRequests && oldestRequests.length > 0) {
        timeRemaining = Math.floor((parseInt(oldestRequests[0]) + this.options.windowMs - now) / 1000);
      }

      return {
        ip,
        currentRequests: parseInt(requestCount) || 0,
        maxRequests: this.options.maxRequests,
        windowMs: this.options.windowMs,
        timeRemaining: timeRemaining || 0,
        isBlocked: this.blockedIpsCache.has(ip)
      };
    } catch (err) {
      this.log(`Error getting rate limit status for IP ${ip}: ${err.message}`, 'error');
      throw err;
    }
  }

  // Setup admin routes for managing blocked IPs
  setupAdminRoutes(router) {
    // Get all blocked IPs
    router.get('/blocked', async (req, res) => {
      try {
        const blockedIPs = await this.getBlockedIPs();
        res.status(200).json({
          count: blockedIPs.length,
          blockedIPs
        });
      } catch (err) {
        res.status(500).json({ error: err.message });
      }
    });

    // Unblock an IP
    router.post('/unblock/:ip', async (req, res) => {
      const ip = req.params.ip;
      try {
        if (this.blockedIpsCache.has(ip)) {
          await this.unblockIP(ip);
          res.status(200).json({ message: `IP ${ip} has been unblocked successfully.` });
        } else {
          res.status(404).json({ error: 'IP address not found in block list.' });
        }
      } catch (err) {
        res.status(500).json({ error: err.message });
      }
    });

    // Manually block an IP
    router.post('/block/:ip', async (req, res) => {
      const ip = req.params.ip;
      const duration = req.body.duration; // Optional duration in milliseconds

      try {
        await this.manuallyBlockIP(ip, duration);
        res.status(200).json({ 
          message: `IP ${ip} has been blocked successfully.`,
          duration: duration || this.options.blockDuration
        });
      } catch (err) {
        res.status(500).json({ error: err.message });
      }
    });

    // Get rate limit status for an IP
    router.get('/status/:ip', async (req, res) => {
      const ip = req.params.ip;
      try {
        const status = await this.getRateLimitStatus(ip);
        res.status(200).json(status);
      } catch (err) {
        res.status(500).json({ error: err.message });
      }
    });

    return router;
  }

  // Create admin router with authentication middleware
  createAdminRouter(authMiddleware = null) {
    const router = express.Router();

    // Apply authentication middleware if provided
    if (authMiddleware) {
      router.use(authMiddleware);
    }

    return this.setupAdminRoutes(router);
  }

  // Clean up resources
  close() {
    this.redisClient.quit();
  }
}

