    @Size(min = 1, message = "At least one item is required")
    @Valid
    @OneToMany(mappedBy = "fulfillmentRequest", cascade = CascadeType.ALL, orphanRemoval = true, fetch = FetchType.EAGER)
    private List<FulfillmentItem> items;

