package com.retail.fulfillment.service;

import com.retail.fulfillment.dto.FulfillmentRequestDto;
import com.retail.fulfillment.dto.FulfillmentItemDto;
import com.retail.fulfillment.model.FulfillmentRequest;
import com.retail.fulfillment.model.FulfillmentItem;
import com.retail.fulfillment.repository.FulfillmentRequestRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.retry.annotation.Backoff;
import org.springframework.retry.annotation.Retryable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class FulfillmentService {

    private final FulfillmentRequestRepository repository;
    private final KafkaTemplate<String, FulfillmentRequest> kafkaTemplate;

    @Transactional
    @Retryable(
        retryFor = {Exception.class},
        maxAttempts = 3,
        backoff = @Backoff(delay = 1000, multiplier = 2)
    )
    public FulfillmentRequest createFulfillment(FulfillmentRequestDto dto) {
        log.info("Creating fulfillment request for order: {}", dto.getOrderId());

        try {
            FulfillmentRequest request = convertToEntity(dto);
            FulfillmentRequest savedRequest = repository.save(request);
            log.info("Saved fulfillment request with ID: {}", savedRequest.getId());

            publishFulfillmentEvent(savedRequest);
            log.info("Published fulfillment event for request: {}", savedRequest.getId());

            return savedRequest;
        } catch (Exception e) {
            log.error("Error creating fulfillment request: {}", e.getMessage(), e);
            throw e;
        }
    }

    @Retryable(
        retryFor = {Exception.class},
        maxAttempts = 3,
        backoff = @Backoff(delay = 500, multiplier = 2)
    )
    private void publishFulfillmentEvent(FulfillmentRequest request) {
        log.info("Publishing fulfillment event for request: {}", request.getId());
        kafkaTemplate.send("fulfillment.requested", request.getId().toString(), request);
    }

    private FulfillmentRequest convertToEntity(FulfillmentRequestDto dto) {
        FulfillmentRequest request = new FulfillmentRequest();
        request.setOrderId(dto.getOrderId());
        request.setWarehouseId(dto.getWarehouseId());
        request.setRequestedShipDate(dto.getRequestedShipDate());

        if (dto.getItems() != null) {
            request.setItems(dto.getItems().stream()
                .map(this::convertItemToEntity)
                .collect(Collectors.toList()));
        }

        return request;
    }

    private FulfillmentItem convertItemToEntity(FulfillmentItemDto dto) {
        FulfillmentItem item = new FulfillmentItem();
        item.setProductId(dto.getProductId());
        item.setQuantity(dto.getQuantity());
        return item;
    }
}

