namespace CurrencyConversionAPI.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class CurrencyController : ControllerBase
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly IMemoryCache _memoryCache;
        private readonly ILogger<CurrencyController> _logger;
        private readonly IApiKeyValidator _apiKeyValidator;

        public CurrencyController(
            IHttpClientFactory httpClientFactory,
            IMemoryCache memoryCache,
            ILogger<CurrencyController> logger,
            IApiKeyValidator apiKeyValidator)
        {
            _httpClientFactory = httpClientFactory ?? throw new ArgumentNullException(nameof(httpClientFactory));
            _memoryCache = memoryCache ?? throw new ArgumentNullException(nameof(memoryCache));
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
            _apiKeyValidator = apiKeyValidator ?? throw new ArgumentNullException(nameof(apiKeyValidator));
        }

        [HttpGet("convert")]
        [SwaggerOperation(Summary = "Converts an amount from one currency to another using real-time exchange rates")]
        [SwaggerResponse(StatusCodes.Status200OK, "The conversion was successful", typeof(ConversionResponse))]
        [SwaggerResponse(StatusCodes.Status400BadRequest, "Input validation failed", typeof(ValidationError))]
        [SwaggerResponse(StatusCodes.Status401Unauthorized, "API key is missing or invalid", typeof(ServiceError))]
        [SwaggerResponse(StatusCodes.Status503ServiceUnavailable, "External rate service unavailable", typeof(ServiceError))]
        public async Task<IActionResult> Convert(
            [FromQuery, Required, RegularExpression(@"^[A-Z]{3}$"), SwaggerParameter("ISO 4217 code of the source currency", Required = true)] string fromCurrency,
            [FromQuery, Required, RegularExpression(@"^[A-Z]{3}$"), SwaggerParameter("ISO 4217 code of the target currency", Required = true)] string toCurrency,
            [FromQuery, Required, Range(0.01, double.MaxValue), SwaggerParameter("Amount to convert", Required = true)] decimal amount)
        {
            string correlationId = Guid.NewGuid().ToString();
            HttpContext.Response.Headers.Add("X-Correlation-Id", correlationId);

            _logger.LogInformation(JsonSerializer.Serialize(new
            {
                CorrelationId = correlationId,
                Operation = "ConvertCurrency",
                FromCurrency = fromCurrency,
                ToCurrency = toCurrency,
                Amount = amount
            }));

            // API key validation
            string apiKey = Request.Headers["X-Api-Key"];
            if (string.IsNullOrEmpty(apiKey) || !_apiKeyValidator.IsValid(apiKey))
            {
                var unauthorizedError = new ServiceError("Unauthorized", "Missing or invalid API key");

                _logger.LogWarning(JsonSerializer.Serialize(new
                {
                    CorrelationId = correlationId,
                    Operation = "ConvertCurrency",
                    Status = StatusCodes.Status401Unauthorized,
                    Message = "Unauthorized access attempt"
                }));

                return Unauthorized(unauthorizedError);
            }

            if (!ModelState.IsValid)
            {
                return BadRequest(new ValidationError(ModelState));
            }

            try
            {
                var cacheKey = $"{fromCurrency}_{toCurrency}";
                if (!_memoryCache.TryGetValue(cacheKey, out decimal exchangeRate))
                {
                    var httpClient = _httpClientFactory.CreateClient("ExchangeRateService");

                    var retryPolicy = Policy
                        .HandleResult<HttpResponseMessage>(r => !r.IsSuccessStatusCode)
                        .WaitAndRetryAsync(
                            3,
                            retryAttempt => TimeSpan.FromSeconds(Math.Pow(2, retryAttempt)),
                            onRetry: (outcome, timespan, retryAttempt, context) =>
                            {
                                _logger.LogWarning(JsonSerializer.Serialize(new
                                {
                                    CorrelationId = correlationId,
                                    Operation = "FetchExchangeRate",
                                    RetryAttempt = retryAttempt,
                                    StatusCode = outcome.Result?.StatusCode
                                }));
                            });

                    var response = await retryPolicy.ExecuteAsync(() => 
                        httpClient.GetAsync($"https://api.exchangeratesapi.io/latest?base={fromCurrency}&symbols={toCurrency}"));

                    if (!response.IsSuccessStatusCode)
                    {
                        _logger.LogError(JsonSerializer.Serialize(new
                        {
                            CorrelationId = correlationId,
                            Operation = "FetchExchangeRate",
                            Status = response.StatusCode,
                            ReasonPhrase = response.ReasonPhrase
                        }));

                        return StatusCode(StatusCodes.Status503ServiceUnavailable, 
                            new ServiceError("Rate service unavailable", response.ReasonPhrase));
                    }

                    var content = await response.Content.ReadAsStringAsync();
                    var rates = JsonSerializer.Deserialize<RatesResponse>(content, 
                        new JsonSerializerOptions { PropertyNameCaseInsensitive = true });

                    if (rates?.Rates == null || !rates.Rates.TryGetValue(toCurrency, out exchangeRate))
                    {
                        _logger.LogError(JsonSerializer.Serialize(new
                        {
                            CorrelationId = correlationId,
                            Operation = "ParseExchangeRate",
                            Error = "Currency not found in response"
                        }));

                        return StatusCode(StatusCodes.Status503ServiceUnavailable, 
                            new ServiceError("Rate service error", "Could not retrieve exchange rate"));
                    }

                    _memoryCache.Set(cacheKey, exchangeRate, TimeSpan.FromMinutes(5));

                    _logger.LogInformation(JsonSerializer.Serialize(new
                    {
                        CorrelationId = correlationId,
                        Operation = "CacheExchangeRate",
                        FromCurrency = fromCurrency,
                        ToCurrency = toCurrency,
                        Rate = exchangeRate
                    }));
                }
                else
                {
                    _logger.LogInformation(JsonSerializer.Serialize(new
                    {
                        CorrelationId = correlationId,
                        Operation = "GetCachedExchangeRate",
                        FromCurrency = fromCurrency,
                        ToCurrency = toCurrency,
                        Rate = exchangeRate
                    }));
                }

                decimal convertedAmount = amount * exchangeRate;
                var result = new ConversionResponse
                {
                    FromCurrency = fromCurrency,
                    ToCurrency = toCurrency,
                    ExchangeRate = exchangeRate,
                    OriginalAmount = amount,
                    ConvertedAmount = convertedAmount,
                    Timestamp = DateTime.UtcNow.ToString("o")
                };

                _logger.LogInformation(JsonSerializer.Serialize(new
                {
                    CorrelationId = correlationId,
                    Operation = "ConvertCurrency",
                    Status = StatusCodes.Status200OK,
                    Result = result
                }));

                return Ok(result);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, JsonSerializer.Serialize(new
                {
                    CorrelationId = correlationId,
                    Operation = "ConvertCurrency",
                    Status = StatusCodes.Status503ServiceUnavailable,
                    Exception = ex.Message
                }));

                return StatusCode(StatusCodes.Status503ServiceUnavailable, 
                    new ServiceError("Rate service unavailable", ex.Message));
            }
        }
    }

    public class ConversionResponse
    {
        public string FromCurrency { get; set; }
        public string ToCurrency { get; set; }
        public decimal ExchangeRate { get; set; }
        public decimal OriginalAmount { get; set; }
        public decimal ConvertedAmount { get; set; }
        public string Timestamp { get; set; }
    }

    public class RatesResponse
    {
        public Dictionary<string, decimal> Rates { get; set; }
    }

    public class ValidationError
    {
        public List<string> Errors { get; set; }

        public ValidationError(ModelStateDictionary modelState)
        {
            Errors = new List<string>();
            foreach (var entry in modelState)
            {
                foreach (var error in entry.Value.Errors)
                {
                    Errors.Add($"{entry.Key}: {error.ErrorMessage}");
                }
            }
        }
    }

    public class ServiceError
    {
        public string Error { get; set; }
        public string Details { get; set; }

        public ServiceError(string error, string details)
        {
            Error = error;
            Details = details;
        }
    }

    public interface IApiKeyValidator
    {
        bool IsValid(string apiKey);
    }
}

