class ReviewService {
  // Create a new review
  async createReview(userId, productId, rating, comment) {
    try {
      const [result] = await pool.execute(
        'INSERT INTO reviews (user_id, product_id, rating, comment, created_at) VALUES (?, ?, ?, ?, NOW())',
        [userId, productId, rating, comment]
      );
      return { id: result.insertId, userId, productId, rating, comment };
    } catch (error) {
      throw new Error(`Failed to create review: ${error.message}`);
    }
  }

  // Get all reviews for a product
  async getReviewsByProduct(productId) {
    try {
      const [rows] = await pool.execute(
        `SELECT r.id, r.rating, r.comment, r.created_at, u.username 
         FROM reviews r
         JOIN users u ON r.user_id = u.id
         WHERE r.product_id = ?
         ORDER BY r.created_at DESC`,
        [productId]
      );
      return rows;
    } catch (error) {
      throw new Error(`Failed to fetch product reviews: ${error.message}`);
    }
  }

  // Get all reviews by a user
  async getReviewsByUser(userId) {
    try {
      const [rows] = await pool.execute(
        `SELECT r.id, r.rating, r.comment, r.created_at, p.name as product_name 
         FROM reviews r
         JOIN products p ON r.product_id = p.id
         WHERE r.user_id = ?
         ORDER BY r.created_at DESC`,
        [userId]
      );
      return rows;
    } catch (error) {
      throw new Error(`Failed to fetch user reviews: ${error.message}`);
    }
  }
}

