    process.exit(1);
  }
  console.log('Connected to MySQL database');
});

// Secure session store
const sessionStore = new MySQLStore(dbOptions);

const app = express();

// Security headers
app.use(helmet());

// Parse request body
app.use(express.json());
app.use(express.urlencoded({ extended: false }));

// HTTPS options
const httpsOptions = {
  key: fs.readFileSync(process.env.SSL_KEY_PATH || 'key.pem'),
  cert: fs.readFileSync(process.env.SSL_CERT_PATH || 'cert.pem')
};

app.use(session({
  key: process.env.SESSION_KEY || 'session_cookie_name',
  secret: process.env.SESSION_SECRET || 'session_cookie_secret',
  store: sessionStore,
  resave: false,
  saveUninitialized: false,
  cookie: {
    httpOnly: true,
    secure: true,
    maxAge: 24 * 60 * 60 * 1000 // 24 hours
  }
}));

app.use(passport.initialize());
app.use(passport.session());

// Rate limit configuration
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // limit each IP to 5 requests per windowMs
  message: 'Too many authentication attempts, please try again later.'
});

// Apply rate limiting to authentication routes
app.use('/auth', authLimiter);

// Passport serializeUser & deserializeUser
passport.serializeUser((user, done) => {
  done(null, user.id);
});

passport.deserializeUser((id, done) => {
  connection.query('SELECT * FROM users WHERE id = ?', [id], (err, results) => {
    if (err) {
      return done(err);
    }
    if (!results.length) {
      return done(null, false);
    }
    done(null, results[0]);
  });
});

// Local strategy for username/password authentication
passport.use(new LocalStrategy(
  {
    usernameField: 'email',
    passwordField: 'password'
  },
  (email, password, done) => {
    connection.query('SELECT * FROM users WHERE email = ?', [email], async (err, results) => {
      if (err) {
        return done(err);
      }
      if (!results.length) {
        return done(null, false, { message: 'Invalid email or password' });
      }

      const user = results[0];
      // Skip password check for OAuth users
      if (!user.password) {
        return done(null, false, { message: 'Please login using OAuth provider' });
      }

      try {
        const passwordMatch = await bcrypt.compare(password, user.password);
        if (passwordMatch) {
          return done(null, user);
        } else {
          return done(null, false, { message: 'Invalid email or password' });
        }
      } catch (error) {
        return done(error);
      }
    });
  }
));

// OAuth strategies
passport.use(new GoogleStrategy({
    clientID: process.env.GOOGLE_CLIENT_ID,
    clientSecret: process.env.GOOGLE_CLIENT_SECRET,
    callbackURL: "/auth/google/callback"
  },
  (accessToken, refreshToken, profile, done) => {
    processOAuthUser(profile, done);
  }
));

passport.use(new FacebookStrategy({
    clientID: process.env.FACEBOOK_CLIENT_ID,
    clientSecret: process.env.FACEBOOK_CLIENT_SECRET,
    callbackURL: "/auth/facebook/callback",
    profileFields: ['id', 'displayName', 'email']
  },
  (accessToken, refreshToken, profile, done) => {
    processOAuthUser(profile, done);
  }
));

passport.use(new GitHubStrategy({
    clientID: process.env.GITHUB_CLIENT_ID,
    clientSecret: process.env.GITHUB_CLIENT_SECRET,
    callbackURL: "/auth/github/callback"
  },
  (accessToken, refreshToken, profile, done) => {
    processOAuthUser(profile, done);
  }
));

// Process OAuth user function
function processOAuthUser(profile, done) {
  const email = profile.emails && profile.emails[0] ? profile.emails[0].value : null;
  if (!email) {
    return done(new Error('Email is required for authentication'));
  }

  connection.query('SELECT * FROM users WHERE oauth_id = ? OR email = ?', [profile.id, email], (err, results) => {
    if (err) {
      return done(err);
    }

    if (results.length) {
      // Update the OAuth ID if user registered with email first
      if (!results[0].oauth_id) {
        connection.query('UPDATE users SET oauth_id = ?, provider = ? WHERE id = ?', 
          [profile.id, profile.provider, results[0].id], 
          (err) => {
            if (err) return done(err);
            return done(null, results[0]);
          }
        );
      } else {
        return done(null, results[0]);
      }
    } else {
      const newUser = {
        oauth_id: profile.id,
        username: profile.displayName,
        provider: profile.provider,
        email: email,
        created_at: new Date()
      };
      connection.query('INSERT INTO users SET ?', newUser, (err, result) => {
        if (err) {
          return done(err);
        }
        newUser.id = result.insertId;
        done(null, newUser);
      });
    }
  });
}

// User registration route
app.post('/auth/register', async (req, res) => {
  try {
    const { username, email, password } = req.body;

    if (!username || !email || !password) {
      return res.status(400).json({ message: 'All fields are required' });
    }

    // Check if user already exists
    connection.query('SELECT * FROM users WHERE email = ?', [email], async (err, results) => {
      if (err) {
        return res.status(500).json({ message: 'Database error' });
      }

      if (results.length) {
        return res.status(409).json({ message: 'User already exists' });
      }

      // Hash password
      const saltRounds = 10;
      const hashedPassword = await bcrypt.hash(password, saltRounds);

      // Create new user
      const newUser = {
        username,
        email,
        password: hashedPassword,
        created_at: new Date()
      };

      connection.query('INSERT INTO users SET ?', newUser, (err, result) => {
        if (err) {
          return res.status(500).json({ message: 'Error creating user' });
        }

        res.status(201).json({ message: 'User registered successfully' });
      });
    });
  } catch (error) {
    res.status(500).json({ message: 'Server error' });
  }
});

